34	// ServerState is the full persistent state for a ddx-server node.
35	// Designed so multiple nodes can eventually forward state to a coordinator.
36	type ServerState struct {
37		SchemaVersion string         `json:"schema_version"`
38		Node          NodeState      `json:"node"`
39		Projects      []ProjectEntry `json:"projects"`
40	
41		mu             sync.RWMutex              `json:"-"`
42		dir            string                    `json:"-"`
43		workingDir     string                    `json:"-"` // root working directory; set post-init by server
44		coordinatorReg *coordinatorRegistry      `json:"-"` // set by Server after workers are created
45		beadIndexMu    sync.RWMutex              `json:"-"`
46		beadIndex      map[string]beadIndexEntry `json:"-"`
47	}
