51	// loadServerState reads state from dir/server-state.json, initialising a fresh state
52	// if the file does not exist. nodeName is the resolved hostname/configured name.
53	func loadServerState(dir, nodeName string) *ServerState {
54		s := &ServerState{
55			SchemaVersion: stateSchemaVersion,
56			dir:           dir,
57			Node: NodeState{
58				Name:      nodeName,
59				ID:        nodeID(nodeName),
60				StartedAt: time.Now().UTC(),
61				LastSeen:  time.Now().UTC(),
62			},
63		}
64	
65		data, err := os.ReadFile(filepath.Join(dir, "server-state.json"))
66		if err != nil {
67			return s // fresh state
68		}
69		var persisted ServerState
70		if err := json.Unmarshal(data, &persisted); err != nil {
71			return s // corrupt — start fresh
72		}
73		// Preserve projects and node ID from prior run; update runtime fields.
74		s.Node.ID = persisted.Node.ID
75		s.Projects = persisted.Projects
76	
77		// Migration: canonicalize paths, resolve linked worktrees, dedupe, sweep.
78		s.migrate()
79		return s
80	}
81	
82	// migrate canonicalises all stored project paths, resolves linked-worktree
83	// paths to the primary worktree, deduplicates entries with the same canonical
84	// path, and marks entries whose paths no longer exist as unreachable. Entries
85	// that are unreachable and whose last_seen is older than 24 h are removed.
86	//
87	// This runs once on startup so a state file that accumulated thousands of
88	// phantom worktree paths is cleaned up automatically.
89	func (s *ServerState) migrate() {
90		now := time.Now().UTC()
91		cutoff := now.Add(-24 * time.Hour)
92	
93		// Pass 1: canonicalize paths (symlinks + abs). We do NOT run git commands
94		// here — linked-worktree resolution happens at RegisterProject time.
95		// Keeping migration git-free makes it safe to run against state files that
96		// contain thousands of temp-dir paths, many of which may exist on disk.
97		for i := range s.Projects {
98			canonical := canonicalizePath(s.Projects[i].Path)
99			if canonical != "" {
100				s.Projects[i].Path = canonical
101				s.Projects[i].Name = filepath.Base(canonical)
102				s.Projects[i].ID = projectID(canonical)
103			}
104		}
105	
106		// Pass 2: dedupe by canonical path — keep earliest RegisteredAt, latest LastSeen.
107		seen := make(map[string]int) // path → index in deduped
108		projects := make([]ProjectEntry, 0, len(s.Projects))
109		for _, p := range s.Projects {
110			if idx, ok := seen[p.Path]; ok {
111				// Merge: keep earliest RegisteredAt, latest LastSeen.
112				if p.RegisteredAt.Before(projects[idx].RegisteredAt) {
113					projects[idx].RegisteredAt = p.RegisteredAt
114				}
115				if p.LastSeen.After(projects[idx].LastSeen) {
116					projects[idx].LastSeen = p.LastSeen
117				}
118				// Keep non-empty git remote.
119				if p.GitRemote != "" && projects[idx].GitRemote == "" {
120					projects[idx].GitRemote = p.GitRemote
121				}
122			} else {
123				seen[p.Path] = len(projects)
124				projects = append(projects, p)
125			}
126		}
127	
128		// Pass 3: reachability sweep — stat each path.
129		kept := make([]ProjectEntry, 0, len(projects))
130		for _, p := range projects {
131			_, statErr := os.Stat(p.Path)
132			if statErr == nil {
133				// Path exists — clear any stale tombstone.
134				p.Unreachable = false
135				p.TombstonedAt = nil
136				kept = append(kept, p)
137				continue
138			}
139			// Path missing. Drop immediately if last seen > 24 h ago (old phantom).
140			if p.LastSeen.Before(cutoff) {
141				continue
142			}
143			// Recently registered but now missing — mark unreachable for GC later.
144			if !p.Unreachable {
145				p.Unreachable = true
146				p.TombstonedAt = &now
147			}
148			kept = append(kept, p)
149		}
150		s.Projects = kept
151	}
