153	func (s *ServerState) save() error {
154		if err := os.MkdirAll(s.dir, 0700); err != nil {
155			return err
156		}
157		s.mu.RLock()
158		defer s.mu.RUnlock()
159		s.Node.LastSeen = time.Now().UTC()
160		data, err := json.MarshalIndent(s, "", "  ")
161		if err != nil {
162			return err
163		}
164		return os.WriteFile(filepath.Join(s.dir, "server-state.json"), data, 0600)
165	}
