167	// RegisterProject adds or updates a project entry. Returns the entry.
168	// The path is canonicalized (symlinks resolved) and, if inside a linked git
169	// worktree, resolved to the primary worktree path before storage.
170	func (s *ServerState) RegisterProject(path string) ProjectEntry {
171		s.mu.Lock()
172		defer s.mu.Unlock()
173	
174		canonical := resolvedProjectPath(path)
175		if canonical == "" {
176			canonical = path
177		}
178	
179		now := time.Now().UTC()
180		id := projectID(canonical)
181		name := filepath.Base(canonical)
182		remote := resolveGitRemote(canonical)
183	
184		for i, p := range s.Projects {
185			if p.ID == id {
186				s.Projects[i].LastSeen = now
187				s.Projects[i].Path = canonical // normalise in case of symlink change
188				s.Projects[i].Name = name
189				// Clear any stale tombstone on re-registration.
190				s.Projects[i].Unreachable = false
191				s.Projects[i].TombstonedAt = nil
192				if remote != "" {
193					s.Projects[i].GitRemote = remote
194				}
195				return s.Projects[i]
196			}
197		}
198	
199		entry := ProjectEntry{
200			ID:           id,
201			Name:         name,
202			Path:         canonical,
203			GitRemote:    remote,
204			RegisteredAt: now,
205			LastSeen:     now,
206		}
207		s.Projects = append(s.Projects, entry)
208		return entry
209	}
