211	// SweepProjects checks each registered project's path on disk.
212	// Paths that no longer exist are marked unreachable with a tombstone timestamp.
213	// Entries tombstoned for more than 24 h are removed.
214	// Returns the post-sweep project list (all entries, including unreachable).
215	func (s *ServerState) SweepProjects() []ProjectEntry {
216		s.mu.Lock()
217		defer s.mu.Unlock()
218	
219		now := time.Now().UTC()
220		cutoff := now.Add(-24 * time.Hour)
221	
222		kept := make([]ProjectEntry, 0, len(s.Projects))
223		for _, p := range s.Projects {
224			_, err := os.Stat(p.Path)
225			if err == nil {
226				// Path exists — clear any stale tombstone.
227				p.Unreachable = false
228				p.TombstonedAt = nil
229				kept = append(kept, p)
230				continue
231			}
232			// Path doesn't exist.
233			if p.TombstonedAt != nil && p.TombstonedAt.Before(cutoff) {
234				// Tombstoned >24 h ago — drop the entry.
235				continue
236			}
237			if !p.Unreachable {
238				// First time marking unreachable.
239				p.Unreachable = true
240				p.TombstonedAt = &now
241			}
242			kept = append(kept, p)
243		}
244		s.Projects = kept
245		return append([]ProjectEntry(nil), s.Projects...)
246	}
