289	// nodeID produces a stable short ID from the node name.
290	func nodeID(name string) string {
291		h := sha256.Sum256([]byte(name))
292		return fmt.Sprintf("node-%x", h[:4])
293	}
294	
295	// projectID produces a stable short ID from the canonical path.
296	func projectID(path string) string {
297		h := sha256.Sum256([]byte(path))
298		return fmt.Sprintf("proj-%x", h[:4])
299	}
