301	// canonicalizePath returns the canonical absolute path, resolving symlinks.
302	// Falls back to filepath.Abs if symlinks cannot be resolved (e.g. path absent).
303	func canonicalizePath(path string) string {
304		abs, err := filepath.Abs(path)
305		if err != nil {
306			return path
307		}
308		resolved, err := filepath.EvalSymlinks(abs)
309		if err != nil {
310			return abs
311		}
312		return resolved
313	}
314	
315	// resolvedProjectPath canonicalizes path and, if it sits inside a linked git
316	// worktree, returns the primary worktree root instead. Returns "" only if
317	// filepath.Abs itself fails (practically impossible).
318	func resolvedProjectPath(path string) string {
319		canonical := canonicalizePath(path)
320		if canonical == "" {
321			return path
322		}
323	
324		// Detect linked worktree via git rev-parse.
325		gitDirOut, err := runGitCapture(canonical, "rev-parse", "--path-format=absolute", "--git-dir")
326		if err != nil {
327			return canonical
328		}
329		gitDir := trimNL(string(gitDirOut))
330	
331		commonDirOut, err := runGitCapture(canonical, "rev-parse", "--path-format=absolute", "--git-common-dir")
332		if err != nil {
333			return canonical
334		}
335		commonDir := trimNL(string(commonDirOut))
336	
337		if gitDir == commonDir {
338			// Not a linked worktree.
339			return canonical
340		}
341	
342		// In a linked worktree. Primary worktree is the parent of the shared .git dir.
343		if filepath.Base(commonDir) == ".git" {
344			return canonicalizePath(filepath.Dir(commonDir))
345		}
346		// Bare repo: no primary worktree — return canonical path.
347		return canonical
348	}
349	
350	// resolveGitRemote returns the origin URL for the repo at path, or "".
351	func resolveGitRemote(path string) string {
352		data, err := runGitCapture(path, "remote", "get-url", "origin")
353		if err != nil {
354			return ""
355		}
356		return trimNL(string(data))
357	}
358	
359	func trimNL(s string) string {
360		for len(s) > 0 && (s[len(s)-1] == '\n' || s[len(s)-1] == '\r') {
361			s = s[:len(s)-1]
362		}
363		return s
364	}
365	
366	// runGitCapture runs a git command in dir and returns its stdout.
367	func runGitCapture(dir string, args ...string) ([]byte, error) {
368		cmd := exec.Command("git", args...) //nolint:gosec
369		cmd.Dir = dir
370		return cmd.Output()
371	}
