3	// TC-011: Host+User State and Node Identity
4	//
5	// Verifies that ddx-server runs as a per-user host daemon with state at
6	// XDG_DATA_HOME/ddx/server-state.json and writes XDG_DATA_HOME/ddx/server.addr,
7	// per FEAT-020. Tests use XDG_DATA_HOME env-var overrides so they never touch
8	// the real user state file.
9	
10	import (
11		"encoding/json"
12		"net/http"
13		"net/http/httptest"
14		"os"
15		"path/filepath"
16		"strings"
17		"testing"
18	)
