20	// stateDir returns the XDG_DATA_HOME/ddx path used by a server started under
21	// the current XDG_DATA_HOME env var (which tests override via t.Setenv).
22	func stateDir(t *testing.T) string {
23		t.Helper()
24		xdg := os.Getenv("XDG_DATA_HOME")
25		if xdg == "" {
26			t.Fatal("XDG_DATA_HOME not set; call t.Setenv before using stateDir")
27		}
28		return filepath.Join(xdg, "ddx")
29	}
