31	// TC-011.1 — Server writes server-state.json under XDG_DATA_HOME/ddx.
32	func TestStateFileLocation(t *testing.T) {
33		t.Setenv("DDX_NODE_NAME", "test-node")
34	
35		// setupTestDir isolates XDG_DATA_HOME to its own temp dir.
36		workDir := setupTestDir(t)
37		xdgDir := os.Getenv("XDG_DATA_HOME")
38		srv := New(":0", workDir)
39	
40		// save() is called internally by New() via RegisterProject; verify the file.
41		stateFile := filepath.Join(xdgDir, "ddx", "server-state.json")
42		data, err := os.ReadFile(stateFile)
43		if err != nil {
44			t.Fatalf("server-state.json not written at %s: %v", stateFile, err)
45		}
46	
47		var state struct {
48			SchemaVersion string `json:"schema_version"`
49			Node          struct {
50				Name string `json:"name"`
51				ID   string `json:"id"`
52			} `json:"node"`
53			Projects []struct {
54				ID   string `json:"id"`
55				Path string `json:"path"`
56			} `json:"projects"`
57		}
58		if err := json.Unmarshal(data, &state); err != nil {
59			t.Fatalf("server-state.json not valid JSON: %v", err)
60		}
61		if state.Node.Name != "test-node" {
62			t.Errorf("expected node name=test-node, got %q", state.Node.Name)
63		}
64		if !strings.HasPrefix(state.Node.ID, "node-") {
65			t.Errorf("expected node ID to start with 'node-', got %q", state.Node.ID)
66		}
67		if len(state.Projects) == 0 {
68			t.Error("expected at least one project in state file")
69		}
70		_ = srv
71	}
