115	// TC-011.3 — GET /api/node returns a stable node-<hash> ID derived from
116	// DDX_NODE_NAME (or hostname). Covered by TestGetNode in server_test.go;
117	// this test adds the stability assertion: two requests must return the same ID.
118	func TestNodeIdentityStable(t *testing.T) {
119		t.Setenv("XDG_DATA_HOME", t.TempDir())
120		t.Setenv("DDX_NODE_NAME", "stable-node")
121	
122		workDir := setupTestDir(t)
123		srv := New(":0", workDir)
124	
125		getNode := func() string {
126			req := httptest.NewRequest("GET", "/api/node", nil)
127			req.RemoteAddr = "127.0.0.1:12345"
128			w := httptest.NewRecorder()
129			srv.Handler().ServeHTTP(w, req)
130			if w.Code != http.StatusOK {
131				t.Fatalf("expected 200, got %d", w.Code)
132			}
133			var node struct {
134				ID string `json:"id"`
135			}
136			if err := json.Unmarshal(w.Body.Bytes(), &node); err != nil {
137				t.Fatalf("invalid JSON: %v", err)
138			}
139			return node.ID
140		}
141	
142		id1 := getNode()
143		id2 := getNode()
144	
145		if !strings.HasPrefix(id1, "node-") {
146			t.Errorf("expected node ID prefix 'node-', got %q", id1)
147		}
148		if id1 != id2 {
149			t.Errorf("node ID changed between requests: %q vs %q", id1, id2)
150		}
151	}
