153	// TC-011.4 — Projects registered before a simulated restart are returned by
154	// GET /api/projects after a fresh server is created against the same state dir.
155	func TestStateFileProjectsPersistAcrossRestart(t *testing.T) {
156		t.Setenv("DDX_NODE_NAME", "persist-node")
157	
158		workDir := setupTestDir(t)
159	
160		// Start first server; it registers workDir automatically.
161		srv1 := New(":0", workDir)
162	
163		// Register an additional project path.
164		extraPath := t.TempDir()
165		srv1.state.RegisterProject(extraPath)
166		if err := srv1.state.save(); err != nil {
167			t.Fatalf("save() failed: %v", err)
168		}
169	
170		// Verify first server has both projects.
171		before := srv1.state.GetProjects()
172		if len(before) != 2 {
173			t.Fatalf("expected 2 projects before restart, got %d", len(before))
174		}
175	
176		// Simulate a restart: create a new Server backed by the same XDG state dir.
177		srv2 := New(":0", workDir)
178	
179		// GET /api/projects on the new server must return the same projects.
180		req := httptest.NewRequest("GET", "/api/projects", nil)
181		req.RemoteAddr = "127.0.0.1:12345"
182		w := httptest.NewRecorder()
183		srv2.Handler().ServeHTTP(w, req)
184	
185		if w.Code != http.StatusOK {
186			t.Fatalf("expected 200, got %d", w.Code)
187		}
188	
189		var projects []struct {
