87	const stateSchemaVersion = "1"
88	
89	// loadServerState reads state from dir/server-state.json, initialising a fresh state
90	// if the file does not exist. nodeName is the resolved hostname/configured name.
91	func loadServerState(dir, nodeName string) *ServerState {
92		s := &ServerState{
93			SchemaVersion: stateSchemaVersion,
94			dir:           dir,
95			Node: NodeState{
96				Name:      nodeName,
97				ID:        nodeID(nodeName),
98				StartedAt: time.Now().UTC(),
99				LastSeen:  time.Now().UTC(),
100			},
101		}
102	
103		data, err := os.ReadFile(filepath.Join(dir, "server-state.json"))
104		if err != nil {
105			return s // fresh state
106		}
107		var persisted ServerState
108		if err := json.Unmarshal(data, &persisted); err != nil {
109			return s // corrupt — start fresh
110		}
111		// Preserve projects and node ID from prior run; update runtime fields.
112		s.Node.ID = persisted.Node.ID
113		s.Projects = persisted.Projects
114	
115		// Migration: canonicalize paths, resolve linked worktrees, dedupe, sweep.
116		phantoms := s.migrate()
117		if phantoms > 0 {
118			log.Printf("ddx-server: pruned %d phantom test-dir projects from state file", phantoms)
119		}
120		return s
121	}
122	
123	// migrate canonicalises all stored project paths, resolves linked-worktree
124	// paths to the primary worktree, deduplicates entries with the same canonical
125	// path, and marks entries whose paths no longer exist as unreachable. Entries
126	// that are unreachable and whose last_seen is older than 24 h are removed.
127	// Test-dir paths (matching IsTestDirPath) are dropped unconditionally — they
128	// are never real user projects, only pollution from tests that forgot to
129	// isolate XDG_DATA_HOME (ddx-15f7ee0b Fix B).
130	//
131	// Returns the number of entries dropped because they matched a test-dir
132	// pattern, so callers can log the cleanup on startup.
133	//
134	// This runs once on startup so a state file that accumulated thousands of
135	// phantom worktree paths is cleaned up automatically.
136	func (s *ServerState) migrate() int {
137		now := time.Now().UTC()
138		cutoff := now.Add(-24 * time.Hour)
139	
140		// Pass 1: canonicalize paths (symlinks + abs). We do NOT run git commands
141		// here — linked-worktree resolution happens at RegisterProject time.
142		// Keeping migration git-free makes it safe to run against state files that
143		// contain thousands of temp-dir paths, many of which may exist on disk.
144		for i := range s.Projects {
145			canonical := canonicalizePath(s.Projects[i].Path)
146			if canonical != "" {
147				s.Projects[i].Path = canonical
148				s.Projects[i].Name = filepath.Base(canonical)
149				s.Projects[i].ID = projectID(canonical)
150			}
151		}
152	
153		// Pass 2: dedupe by canonical path — keep earliest RegisteredAt, latest LastSeen.
154		seen := make(map[string]int) // path → index in deduped
155		projects := make([]ProjectEntry, 0, len(s.Projects))
156		for _, p := range s.Projects {
157			if idx, ok := seen[p.Path]; ok {
158				// Merge: keep earliest RegisteredAt, latest LastSeen.
159				if p.RegisteredAt.Before(projects[idx].RegisteredAt) {
160					projects[idx].RegisteredAt = p.RegisteredAt
161				}
162				if p.LastSeen.After(projects[idx].LastSeen) {
163					projects[idx].LastSeen = p.LastSeen
164				}
165				// Keep non-empty git remote.
166				if p.GitRemote != "" && projects[idx].GitRemote == "" {
167					projects[idx].GitRemote = p.GitRemote
168				}
169			} else {
170				seen[p.Path] = len(projects)
171				projects = append(projects, p)
172			}
173		}
174	
175		// Pass 3: reachability + test-dir sweep.
176		phantoms := 0
177		kept := make([]ProjectEntry, 0, len(projects))
178		for _, p := range projects {
179			if IsTestDirPath(p.Path) {
180				// Test-dir pollution is never a real user project. Drop whether or
181				// not the path currently exists on disk — a transient temp dir
182				// should never survive a restart.
183				phantoms++
184				continue
185			}
186			_, statErr := os.Stat(p.Path)
187			if statErr == nil {
188				// Path exists — clear any stale tombstone.
189				p.Unreachable = false
190				p.TombstonedAt = nil
191				kept = append(kept, p)
192				continue
193			}
194			// Path missing. Drop immediately if last seen > 24 h ago (old phantom).
195			if p.LastSeen.Before(cutoff) {
196				continue
197			}
198			// Recently registered but now missing — mark unreachable for GC later.
199			if !p.Unreachable {
200				p.Unreachable = true
201				p.TombstonedAt = &now
202			}
203			kept = append(kept, p)
204		}
205		s.Projects = kept
206		return phantoms
207	}
208	
209	func (s *ServerState) save() error {
210		if err := os.MkdirAll(s.dir, 0700); err != nil {
211			return err
212		}
213		s.mu.RLock()
214		defer s.mu.RUnlock()
215		s.Node.LastSeen = time.Now().UTC()
216		data, err := json.MarshalIndent(s, "", "  ")
217		if err != nil {
218			return err
219		}
220		return os.WriteFile(filepath.Join(s.dir, "server-state.json"), data, 0600)
221	}
222	
223	// RegisterProject adds or updates a project entry. Returns the entry.
224	// The path is canonicalized (symlinks resolved) and, if inside a linked git
225	// worktree, resolved to the primary worktree path before storage.
226	func (s *ServerState) RegisterProject(path string) ProjectEntry {
227		s.mu.Lock()
228		defer s.mu.Unlock()
229	
230		canonical := resolvedProjectPath(path)
231		if canonical == "" {
232			canonical = path
233		}
234	
235		now := time.Now().UTC()
236		id := projectID(canonical)
237		name := filepath.Base(canonical)
238		remote := resolveGitRemote(canonical)
239	
240		for i, p := range s.Projects {
241			if p.ID == id {
242				s.Projects[i].LastSeen = now
243				s.Projects[i].Path = canonical // normalise in case of symlink change
244				s.Projects[i].Name = name
245				// Clear any stale tombstone on re-registration.
246				s.Projects[i].Unreachable = false
247				s.Projects[i].TombstonedAt = nil
248				if remote != "" {
249					s.Projects[i].GitRemote = remote
250				}
251				return s.Projects[i]
252			}
253		}
254	
255		entry := ProjectEntry{
256			ID:           id,
257			Name:         name,
258			Path:         canonical,
259			GitRemote:    remote,
260			RegisteredAt: now,
261			LastSeen:     now,
262		}
263		s.Projects = append(s.Projects, entry)
264		return entry
265	}
266	
267	// SweepProjects checks each registered project's path on disk.
268	// Paths that no longer exist are marked unreachable with a tombstone timestamp.
269	// Entries tombstoned for more than 24 h are removed.
270	// Test-dir paths (matching IsTestDirPath) are dropped on every sweep whether
271	// or not they still exist on disk — they are never real user projects.
272	// Returns the post-sweep project list (all entries, including unreachable).
273	func (s *ServerState) SweepProjects() []ProjectEntry {
274		s.mu.Lock()
275		defer s.mu.Unlock()
276	
277		now := time.Now().UTC()
278		cutoff := now.Add(-24 * time.Hour)
279	
280		kept := make([]ProjectEntry, 0, len(s.Projects))
281		for _, p := range s.Projects {
282			if IsTestDirPath(p.Path) {
283				// Test-dir pollution — drop unconditionally.
284				continue
285			}
286			_, err := os.Stat(p.Path)
287			if err == nil {
288				// Path exists — clear any stale tombstone.
289				p.Unreachable = false
290				p.TombstonedAt = nil
291				kept = append(kept, p)
292				continue
293			}
294			// Path doesn't exist.
295			if p.TombstonedAt != nil && p.TombstonedAt.Before(cutoff) {
296				// Tombstoned >24 h ago — drop the entry.
297				continue
298			}
299			if !p.Unreachable {
300				// First time marking unreachable.
301				p.Unreachable = true
302				p.TombstonedAt = &now
303			}
304			kept = append(kept, p)
305		}
306		s.Projects = kept
307		return append([]ProjectEntry(nil), s.Projects...)
308	}
309	
310	// GetProjects returns a snapshot of registered projects.
311	// When includeUnreachable is false (the default for API callers), entries
312	// marked as unreachable are omitted.
313	func (s *ServerState) GetProjects(includeUnreachable ...bool) []ProjectEntry {
314		s.mu.RLock()
315		defer s.mu.RUnlock()
316		showAll := len(includeUnreachable) > 0 && includeUnreachable[0]
317		out := make([]ProjectEntry, 0, len(s.Projects))
318		for _, p := range s.Projects {
319			if !showAll && p.Unreachable {
320				continue
321			}
322			out = append(out, p)
323		}
324		return out
325	}
326	
327	// GetProjectByID returns the project entry with the given ID, if any.
328	func (s *ServerState) GetProjectByID(id string) (ProjectEntry, bool) {
329		s.mu.RLock()
330		defer s.mu.RUnlock()
331		for _, p := range s.Projects {
332			if p.ID == id {
333				return p, true
334			}
335		}
336		return ProjectEntry{}, false
337	}
338	
339	// GetProjectByPath returns the project entry with the given path, if any.
340	func (s *ServerState) GetProjectByPath(path string) (ProjectEntry, bool) {
341		s.mu.RLock()
342		defer s.mu.RUnlock()
343		for _, p := range s.Projects {
344			if p.Path == path {
345				return p, true
346			}
347		}
348		return ProjectEntry{}, false
349	}
350	
351	// nodeID produces a stable short ID from the node name.
352	func nodeID(name string) string {
353		h := sha256.Sum256([]byte(name))
354		return fmt.Sprintf("node-%x", h[:4])
355	}
356	
357	// projectID produces a stable short ID from the canonical path.
358	func projectID(path string) string {
359		h := sha256.Sum256([]byte(path))
360		return fmt.Sprintf("proj-%x", h[:4])
361	}
362	
363	// canonicalizePath returns the canonical absolute path, resolving symlinks.
364	// Falls back to filepath.Abs if symlinks cannot be resolved (e.g. path absent).
365	func canonicalizePath(path string) string {
366		abs, err := filepath.Abs(path)
367		if err != nil {
368			return path
369		}
370		resolved, err := filepath.EvalSymlinks(abs)
371		if err != nil {
372			return abs
373		}
374		return resolved
375	}
376	
377	// resolvedProjectPath canonicalizes path and, if it sits inside a linked git
378	// worktree, returns the primary worktree root instead. Returns "" only if
379	// filepath.Abs itself fails (practically impossible).
380	func resolvedProjectPath(path string) string {
381		canonical := canonicalizePath(path)
382		if canonical == "" {
383			return path
384		}
385	
386		// Detect linked worktree via git rev-parse.
387		gitDirOut, err := runGitCapture(canonical, "rev-parse", "--path-format=absolute", "--git-dir")
388		if err != nil {
389			return canonical
390		}
391		gitDir := trimNL(string(gitDirOut))
392	
393		commonDirOut, err := runGitCapture(canonical, "rev-parse", "--path-format=absolute", "--git-common-dir")
394		if err != nil {
395			return canonical
396		}
397		commonDir := trimNL(string(commonDirOut))
398	
399		if gitDir == commonDir {
400			// Not a linked worktree.
401			return canonical
402		}
403	
404		// In a linked worktree. Primary worktree is the parent of the shared .git dir.
405		if filepath.Base(commonDir) == ".git" {
406			return canonicalizePath(filepath.Dir(commonDir))
407		}
408		// Bare repo: no primary worktree — return canonical path.
409		return canonical
410	}
411	
412	// resolveGitRemote returns the origin URL for the repo at path, or "".
413	func resolveGitRemote(path string) string {
414		data, err := runGitCapture(path, "remote", "get-url", "origin")
415		if err != nil {
416			return ""
417		}
418		return trimNL(string(data))
419	}
420	
421	func trimNL(s string) string {
422		for len(s) > 0 && (s[len(s)-1] == '\n' || s[len(s)-1] == '\r') {
423			s = s[:len(s)-1]
424		}
425		return s
426	}
427	
428	// runGitCapture runs a git command in dir and returns its stdout.
429	func runGitCapture(dir string, args ...string) ([]byte, error) {
430		cmd := exec.Command("git", args...) //nolint:gosec
431		cmd.Dir = dir
432		return cmd.Output()
433	}
434

