package server

// Perf-amplifier regression for ddx-15f7ee0b AC §4: GetBeadSnapshots must not
// open bead stores for projects that are tombstoned (Unreachable=true) or
// whose path matches the test-dir filter. These are the two populations that
// blew up under the pre-fix bug — a polluted state file amplified every
// cross-project query by the number of dead entries.

import (
	"testing"
	"time"
)

func TestGetBeadSnapshotsSkipsTombstonedAndTestDirProjects(t *testing.T) {
	// Arrange a hand-built ServerState. We do not call server.New() here
	// because we want complete control over which entries are present —
	// New() would wipe test-dir entries during loadServerState's migrate.
	withTestDirFilterDisabled(t) // keep test-dir entries visible in the slice
	s := &ServerState{}
	now := time.Now().UTC()
	s.Projects = []ProjectEntry{
		{ID: "real", Path: "/home/example/real", RegisteredAt: now, LastSeen: now},
		{ID: "tomb", Path: "/home/example/tombstoned", RegisteredAt: now, LastSeen: now, Unreachable: true, TombstonedAt: &now},
		{ID: "tdir", Path: "/tmp/TestSkipMe1234/001", RegisteredAt: now, LastSeen: now},
	}

	// Install the hook that records every (proj path) GetBeadSnapshots
	// opens via bead.NewStore — any call for a tombstoned or test-dir
	// entry is a regression.
	opened := make([]string, 0, 3)
	prev := beadStoreOpenHook
	beadStoreOpenHook = func(p string) { opened = append(opened, p) }
	t.Cleanup(func() { beadStoreOpenHook = prev })

	// Run a cross-project snapshot query with no filters. The returned
	// slice may be empty because no bead store exists on disk for the
	// real path either — we only care about which paths were *attempted*.
	_ = s.GetBeadSnapshots("", "", "", "")

	for _, p := range opened {
		if p == "/home/example/tombstoned" {
			t.Errorf("GetBeadSnapshots opened store for tombstoned project %q", p)
		}
		if IsTestDirPathIgnoreOverride(p) {
			t.Errorf("GetBeadSnapshots opened store for test-dir project %q", p)
		}
	}
	// We still expect the real project to have been attempted once.
	realSeen := false
	for _, p := range opened {
		if p == "/home/example/real" {
			realSeen = true
		}
	}
	if !realSeen {
		t.Errorf("expected real project /home/example/real to be opened; opened=%v", opened)
	}
}

// IsTestDirPathIgnoreOverride runs the IsTestDirPath check while bypassing the
// test-only override — exported only to the test binary via this _test.go file.
// Used by the perf-skip regression so the assertion holds even when the outer
// test has called withTestDirFilterDisabled(t).
func IsTestDirPathIgnoreOverride(path string) bool {
	testDirFilterOverrideMu.RLock()
	saved := testDirFilterOverride
	testDirFilterOverride = nil
	testDirFilterOverrideMu.RUnlock()
	defer func() {
		testDirFilterOverrideMu.Lock()
		testDirFilterOverride = saved
		testDirFilterOverrideMu.Unlock()
	}()
	return IsTestDirPath(path)
}

