// callName returns the last identifier of a call expression, e.g. "New" for
// `server.New(...)` or `New(...)`. Methods like `t.Setenv` return "Setenv".
// Returns "" for call expressions that are not identifier-based (e.g. calls
// on anonymous functions).
func callName(fn ast.Expr) string {
	switch v := fn.(type) {
	case *ast.Ident:
		return v.Name
	case *ast.SelectorExpr:
		return v.Sel.Name
	}
	return ""
